     1→import { useEffect, useRef, useState } from "react";
     2→import "./PropertiesPanel.css";
     3→import type { FrontmatterValue, ParsedFrontmatter } from "../lib/frontmatter";
     4→
     5→interface PropertiesPanelProps {
     6→  frontmatter: ParsedFrontmatter;
     7→  isOpen: boolean;
     8→  onToggle: () => void;
     9→  onFieldChange?: (key: string, value: FrontmatterValue) => void;
    10→}
    11→
    12→function formatDate(value: string): string {
    13→  try {
    14→    return new Intl.DateTimeFormat(undefined, { dateStyle: "medium" }).format(
    15→      new Date(`${value}T00:00:00`)
    16→    );
    17→  } catch {
    18→    return value;
    19→  }
    20→}
    21→
    22→const FIELD_ORDER = ["title", "date", "tags", "draft"];
    23→
    24→function toInputString(v: FrontmatterValue): string {
    25→  if (Array.isArray(v)) return v.join(", ");
    26→  if (v === null || v === undefined) return "";
    27→  return String(v);
    28→}
    29→
    30→function sortedKeys(frontmatter: ParsedFrontmatter): string[] {
    31→  const known = FIELD_ORDER.filter((k) => k in frontmatter);
    32→  const rest = Object.keys(frontmatter)
    33→    .filter((k) => !FIELD_ORDER.includes(k))
    34→    .sort();
    35→  return [...known, ...rest];
    36→}
    37→
    38→interface EditableValueProps {
    39→  fieldKey: string;
    40→  value: FrontmatterValue;
    41→  onSave: (newValue: FrontmatterValue) => void;
    42→}
    43→
    44→function EditableValue({ fieldKey, value, onSave }: EditableValueProps) {
    45→  const [editing, setEditing] = useState(false);
    46→  const inputRef = useRef<HTMLInputElement>(null);
    47→  const [draft, setDraft] = useState(toInputString(value));
    48→
    49→  // Sync draft when value is updated externally (e.g. frontmatter written from disk)
    50→  useEffect(() => {
    51→    if (!editing) {
    52→      setDraft(toInputString(value));
    53→    }
    54→  }, [value, editing]);
    55→
    56→  function startEdit() {
    57→    setDraft(toInputString(value));
    58→    setEditing(true);
    59→    // Focus on next tick after render
    60→    setTimeout(() => inputRef.current?.focus(), 0);
    61→  }
    62→
    63→  function commit() {
    64→    const trimmed = draft.trim();
    65→    if (Array.isArray(value)) {
    66→      setEditing(false);
    67→      // Parse comma-separated back to array
    68→      const arr = trimmed
    69→        ? trimmed
    70→            .split(",")
    71→            .map((t) => t.trim())
    72→            .filter(Boolean)
    73→        : [];
    74→      onSave(arr);
    75→    } else if (typeof value === "boolean") {
    76→      const normalized = trimmed.toLowerCase();
    77→      if (normalized !== "true" && normalized !== "false") {
    78→        // Invalid input — keep editing mode, reset draft, bail without saving
    79→        setDraft(toInputString(value));
    80→        return;
    81→      }
    82→      setEditing(false);
    83→      onSave(normalized === "true");
    84→    } else if (typeof value === "number") {
    85→      setEditing(false);
    86→      const num = Number(trimmed);
    87→      onSave(Number.isNaN(num) ? value : num);
    88→    } else {
    89→      setEditing(false);
    90→      onSave(trimmed || null);
    91→    }
    92→  }
    93→
    94→  function cancel() {
    95→    setEditing(false);
    96→    setDraft(toInputString(value));
    97→  }
    98→
    99→  if (editing) {
   100→    return (
   101→      <input
   102→        ref={inputRef}
   103→        className="prop-edit-input"
   104→        value={draft}
   105→        onChange={(e) => setDraft(e.target.value)}
   106→        onKeyDown={(e) => {
   107→          if (e.key === "Enter") commit();
   108→          else if (e.key === "Escape") cancel();
   109→        }}
   110→        onBlur={commit}
   111→        // Prevent sidebar keyboard shortcuts from firing while editing
   112→        onKeyUp={(e) => e.stopPropagation()}
   113→      />
   114→    );
   115→  }
   116→
   117→  // For tags: show tag chips, click any to edit
   118→  if (fieldKey === "tags" && Array.isArray(value)) {
   119→    return (
   120→      <button
   121→        type="button"
   122→        className="prop-editable-area"
   123→        onClick={startEdit}
   124→        title="Click to edit"
   125→      >
   126→        {value.map((tag) => (
   127→          <span key={tag} className="prop-tag">
   128→            {tag}
   129→          </span>
   130→        ))}
   131→        {value.length === 0 && <span className="prop-value prop-empty">add tags…</span>}
   132→      </button>
   133→    );
   134→  }
   135→
   136→  if (fieldKey === "date" && typeof value === "string") {
   137→    return (
   138→      <button
   139→        type="button"
   140→        className="prop-editable-area"
   141→        onClick={startEdit}
   142→        title="Click to edit"
   143→      >
   144→        <span className="prop-value">{formatDate(value)}</span>
   145→      </button>
   146→    );
   147→  }
   148→
   149→  if (fieldKey === "title") {
   150→    return (
   151→      <button
   152→        type="button"
   153→        className="prop-editable-area"
   154→        onClick={startEdit}
   155→        title="Click to edit"
   156→      >
   157→        <span className="prop-value prop-title">{String(value)}</span>
   158→      </button>
   159→    );
   160→  }
   161→
   162→  return (
   163→    <button type="button" className="prop-editable-area" onClick={startEdit} title="Click to edit">
   164→      <span className="prop-value">{String(value ?? "")}</span>
   165→    </button>
   166→  );
   167→}
   168→
   169→export function PropertiesPanel({
   170→  frontmatter,
   171→  isOpen,
   172→  onToggle,
   173→  onFieldChange,
   174→}: PropertiesPanelProps) {
   175→  const keys = sortedKeys(frontmatter);
   176→
   177→  return (
   178→    <div className={`properties-wrapper ${isOpen ? "" : "panel-closed"}`}>
   179→      <div className={`properties-panel ${isOpen ? "open" : "closed"}`}>
   180→        <div className="properties-inner">
   181→          {keys.map((key) => {
   182→            const val = frontmatter[key];
