   489→#[tauri::command]
   490→fn get_content_types(state: State<'_, WorkspaceState>) -> Result<Vec<ContentType>, String> {
   491→    let root_guard = state.workspace_root.lock().map_err(|e| e.to_string())?;
   492→    let root = match root_guard.as_ref() {
   493→        Some(r) => r.clone(),
   494→        None => return Ok(Vec::new()),
   495→    };
   496→    drop(root_guard);
   497→    let config = root.join("site.config.ts");
   498→    if !config.is_file() {
   499→        return Ok(Vec::new());
   500→    }
   501→    Ok(parse_content_types(&config))
   502→}
