/* Tiptap / ProseMirror editor styles */

.editor-wrapper {
  flex: 1;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  background: var(--color-bg);
}

.editor-scroll {
  flex: 1;
  overflow-y: auto;
  padding: 48px 0;
}

.ProseMirror {
  max-width: 680px;
  margin: 0 auto;
  padding: 0 24px;
  font-family: var(--font-editor);
  font-size: var(--font-editor-size, 17px);
  line-height: 1.75;
  color: var(--color-text);
  outline: none;
  min-height: 100%;
}

/* Headings */
.ProseMirror h1 {
  font-size: 2em;
  font-weight: 700;
  line-height: 1.25;
  margin-top: 1.5em;
  margin-bottom: 0.5em;
  color: var(--color-text);
}

.ProseMirror h2 {
  font-size: 1.5em;
  font-weight: 600;
  line-height: 1.3;
  margin-top: 1.4em;
  margin-bottom: 0.4em;
}

.ProseMirror h3 {
  font-size: 1.2em;
  font-weight: 600;
  line-height: 1.35;
  margin-top: 1.3em;
  margin-bottom: 0.35em;
}

/* First heading at top — no extra top margin */
.ProseMirror > h1:first-child,
.ProseMirror > h2:first-child,
.ProseMirror > h3:first-child {
  margin-top: 0;
}

/* Paragraphs */
.ProseMirror p {
  margin-bottom: 1em;
}

.ProseMirror p:last-child {
  margin-bottom: 0;
}

/* Bold & Italic */
.ProseMirror strong {
  font-weight: 700;
}

.ProseMirror em {
  font-style: italic;
}

/* Inline code */
.ProseMirror code {
  font-family: var(--font-mono);
  font-size: 0.875em;
  background: var(--color-bg-selected);
  border: 1px solid var(--color-border);
  border-radius: 3px;
  padding: 0.1em 0.35em;
}

/* Code block */
.ProseMirror pre {
  font-family: var(--font-mono);
  font-size: 0.875em;
  background: var(--color-bg-sidebar);
  border: 1px solid var(--color-border);
  border-radius: 6px;
  padding: 16px 20px;
  overflow-x: auto;
  margin: 1.2em 0;
  line-height: 1.6;
}

.ProseMirror pre code {
  background: none;
  border: none;
  padding: 0;
  font-size: 1em;
}

/* Blockquote */
.ProseMirror blockquote {
  border-left: 3px solid var(--color-accent);
  padding-left: 1em;
  margin: 1.2em 0;
  color: var(--color-text-muted);
  font-style: italic;
}

/* Lists */
.ProseMirror ul,
.ProseMirror ol {
  padding-left: 1.5em;
  margin: 0.75em 0;
}

.ProseMirror li {
  margin-bottom: 0.25em;
}

/* Horizontal rule */
.ProseMirror hr {
  border: none;
  border-top: 1px solid var(--color-border);
  margin: 2em 0;
}

/* Links */
.ProseMirror a {
  color: var(--color-accent);
  text-decoration: underline;
  text-underline-offset: 2px;
}

/* Images */
.ProseMirror img {
  max-width: 100%;
  border-radius: 6px;
  margin: 1em 0;
}

/* Placeholder */
.ProseMirror p.is-editor-empty:first-child::before {
  content: attr(data-placeholder);
  color: var(--color-text-faint);
  pointer-events: none;
  float: left;
  height: 0;
  font-family: var(--font-ui);
  font-style: normal;
}

/* Selection */
.ProseMirror ::selection {
  background: var(--color-accent-light);
}

/* Focus ring — hidden, we style it via the wrapper */
.ProseMirror:focus {
  outline: none;
}

/* ── Syntax highlighting (lowlight/highlight.js tokens) ─── */
.hljs-comment,
.hljs-quote {
  color: var(--color-syntax-comment);
  font-style: italic;
}

.hljs-keyword,
.hljs-selector-tag,
.hljs-built_in,
.hljs-name,
.hljs-tag {
  color: var(--color-syntax-keyword);
}

.hljs-string,
.hljs-title,
.hljs-section,
.hljs-attribute,
.hljs-literal,
.hljs-template-tag,
.hljs-template-variable,
.hljs-type,
.hljs-addition {
  color: var(--color-syntax-string);
}

.hljs-deletion,
.hljs-selector-attr,
.hljs-selector-pseudo,
.hljs-meta {
  color: var(--color-syntax-meta);
}

.hljs-doctag,
.hljs-attr {
  color: var(--color-syntax-attr);
}

.hljs-symbol,
.hljs-bullet,
.hljs-link,
.hljs-subst,
.hljs-variable,
.hljs-number,
.hljs-regexp {
  color: var(--color-syntax-number);
}

.hljs-emphasis {
  font-style: italic;
}

.hljs-strong {
  font-weight: bold;
}

/* Link preview tooltip */
.link-preview-tooltip {
  position: fixed;
  z-index: 1000;
  display: none;
  max-width: 360px;
  background: var(--color-bg-sidebar);
  border: 1px solid var(--color-border-strong);
  border-radius: 6px;
  padding: 5px 10px;
  font-size: 12px;
  font-family: var(--font-ui);
  color: var(--color-text-muted);
  pointer-events: none;
  box-shadow: 0 4px 12px var(--shadow-tooltip);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

