  });
  return () => unlisten?.();
}, [
  workspaceRoot,
  tree,
  isGitRepo,
  getBranch,
  parsedFrontmatter,
  selectedFile,
  showToast,
  flushPendingSave,
  handleCloseFile,
  handleOpenWorkspace,
]);

